/** @jsxImportSource @emotion/react */
import { css } from '@emotion/react';

type CardProps = React.ButtonHTMLAttributes<HTMLDivElement> & {
  title?: string;
  description?: React.ReactNode;
  image?: string;
};

export function Card({ title, description, children,image, ...containerProps }: CardProps) {
  return (
    <div css={styles.card} {...containerProps}>
  
        {children != null && <div css={styles.children}>{children}</div>}
      </div>
   
  );
}

const styles = {
  card: css`
    background-color: #fff;
    border-radius: 4px;
    box-shadow: 0px 4px 8px rgba(0, 0, 0, 0.1);
    display: flex;
    flex-direction: column;
    overflow: hidden;
  `,
  image: css`
    height: 200px;
    width" 100%';
    object-fit: cover;
  `,
  content: css`
    padding: 16px;
  `,
  title: css`
    font-size: 24px;
    font-weight: bold;
    margin: 0 0 8px 0;
  `,
  description: css`
    font-size: 16px;
    margin: 0;
  `,
  children: css`
    margin-top: 8px;
    padding-top: 8px;
    border-top: 1px solid rgba(0, 0, 0, 0.2);
  `,
};
